"""llm_providers bootstrap: populate the module settings store."""from __future__ import annotationsfrom pathlib import Pathfrom .interfaces.response_logger import ResponseLoggerProtocolfrom .module import LLMProvidersConfig, ModuleParams, ModuleStoredef module_llm_providers_boot(    config: LLMProvidersConfig,    *,    response_logger: ResponseLoggerProtocol | None = None,    cache_path: Path | str | None = None,) -> None:    """    Primary module init: store config and optional cache dir.    If cache_path is set: use as ModuleParams.cache_path and ensure dir exists.    If None: cache disabled.    """    if cache_path is not None:        cache_path_resolved = Path(cache_path).resolve()        cache_path_resolved.mkdir(parents=True, exist_ok=True)    else:        cache_path_resolved = None    ModuleStore.setup(        ModuleParams(providers=config, response_logger=response_logger, cache_path=cache_path_resolved)    )